SELECT COUNT(user_id) 
  FROM user_product_access
  WHERE product_id = 1 AND access_level = 'read-write';

SELECT DISTINCT pd.product_id
FROM product_documents pd
WHERE pd.document_type = 'Datasheet' AND pd.file_size > 1;

SELECT DISTINCT product_id
FROM user_product_access
WHERE access_level = 'read-write';

SELECT product_id, document_type
FROM product_documents
WHERE revision > 0;

SELECT category_name
FROM product_categories
WHERE category_id NOT IN (
  SELECT DISTINCT product_id
  FROM product_documents
);

SELECT product_id, MAX(file_size) AS max_file_size
FROM product_documents
GROUP BY product_id;
